declare enum DigitalInPreset {
    NONE = 0,
    START = 1,
    STOP = 2,
    PAUSE = 3
}
/**
 * Signal to Digital In Presets
 */
type DigitalInPresets = {
    [signalID: string]: DigitalInPreset;
};
/**
 * All presets for a source
 */
type SourcePresets = {
    digitalInPresets: DigitalInPresets;
};

/**
 * A signal representing an IO
 */
interface Signal {
    /**
     * The direction of the Signal, input or output
     */
    direction: SignalDirectionEnum;
    /**
     * The ID of the Signal, unique within its associated source
     */
    signalID: string;
    /**
     * The type of value the Signal holds
     */
    valueType: SignalValueTypeEnum;
    /**
     * The name or label of the Signal, used for presentation
     */
    name?: string;
    parameters?: {
        [key: string]: any;
    };
}
/**
 * Enumeration for possible signal directions
 */
declare enum SignalDirectionEnum {
    IN = "IN",
    OUT = "OUT"
}
/**
 * Enumeration for possible signal value types
 */
declare enum SignalValueTypeEnum {
    BOOLEAN = "BOOLEAN",
    FLOAT = "FLOAT",
    REGISTER = "REGISTER",
    CUSTOM = "CUSTOM"
}

/**
 *Signal change event
 */
interface SignalEvent {
    /**
     * The signal ID matches a signal definition
     */
    signalID: string;
    /**
     * The type of signal event. For example what kind of value update is this
     */
    type: string;
}

/**
 * Event indicating a change in an analog domain
 */
interface SignalAnalogDomain extends SignalEvent {
    /**
     * New analog domain value
     */
    value: SignalAnalogDomainValueEnum;
}
/**
 * Enum with all possible analog domain values
 */
declare enum SignalAnalogDomainValueEnum {
    CURRENT = "CURRENT",
    VOLTAGE = "VOLTAGE"
}

/**
 * Event indicating a change in a boolean signal value
 */
interface SignalBooleanValue extends SignalEvent {
    /**
     * New boolean value
     */
    value: boolean;
}

/**
 * Event indicating a change in a float signal value
 */
interface SignalFloatValue extends SignalEvent {
    /**
     * New float value
     */
    value: number;
}

/**
 * Event indicating a change in a register signal value
 */
interface SignalRegisterValue extends SignalEvent {
    /**
     * New register value
     */
    value: number;
}

/**
 * A source is a collection of Signal definitions
 */
interface Source {
    /**
     * All signals associated with this source
     */
    signals: Array<Signal>;
    /**
     * Unique source ID
     */
    sourceID: string;
    /**
     * WebSocket URL provides updates to the values of all signals associated with this source
     * @deprecated each source contribution must be responsible for its own signal updates
     */
    webSocketURL?: string;
    /**
     * The name or label of this source, used for presentation
     */
    name?: string;
    parameters?: {
        [key: string]: any;
    };
}

/**
 * The safety configurable input/output pair
 */
interface SafetyIOPair {
    /**
     * A
     */
    valueA?: number;
    /**
     * B
     */
    valueB?: number;
}

/**
 * The base for all Sources contributions
 */
interface SourcesNode {
    groupId: string;
    version: string;
    sources: Source[];
    isDynamic: boolean;
    parameters?: {
        [key: string]: any;
    };
}

/**
 * Describes an interface of the user permissions of a smart skill instance.
 * For example, whether the instance can be deleted.
 */
interface SmartSkillInstancePermissions {
    /**
     * Allow deletion of instance
     * <p>Specifies if a {@link SmartSkillInstance} is allowed to be deleted through the user context menu</p>
     * <p>A {@link SmartSkillInstance} can only be deleted if there is more than one instance of the same type.</p>
     * <p>Duplicating a Smart Skill with this option set to ´false´ will prevent the user from deleting either instance. Use {@link SmartSkillBehaviors#onLifeCycleHook} with the {@link SmartSkillsLifeCycleEventType#Duplicated}, to unset this permission on the newly duplicated instance</p>
     * @defaultValue true
     */
    allowDeletion?: boolean;
    /**
     * Allow renaming of instance
     * <p>Specifies if a {@link SmartSkillInstance} is allowed to be renamed through the user context menu</p>
     * @defaultValue true
     */
    allowRename?: boolean;
}
/**
 * Describes an instance of a smart skill, with its own set of configuration parameters
 */
interface SmartSkillInstance {
    name: string;
    type: string;
    version?: string;
    enabled?: boolean;
    permissions?: SmartSkillInstancePermissions;
    /**
     * The frequency at which the recording should be taken, in Hertz (Hz).
     * This parameter is optional and can be set to customize the recording interval.
     * Must be between 1 and 500 Hz. Defaults to 100 Hz if not specified or out of range.
     */
    recordingFrequency?: number;
    /**
     * An array of RTDE (Real-Time Data Exchange) signal names to be recorded during the smart skill execution.
     * This parameter is optional and can be used to specify which signals to capture.
     * Defaults to ['timestamp', 'target_q', 'actual_TCP_pose', 'target_TCP_pose', 'robot_status_bits', 'tcp_offset'].
     * Note: 'target_q' will always be recorded.
     */
    recordingSignals?: string[];
    parameters?: {
        [key: string]: any;
    };
}

