/**
 * Describes the payload limits.
 */
interface PayloadLimits {
    /**
     * The robot payload soft limit.
     */
    softLimit: Mass;
    /**
     * The robot payload hard limit.
     */
    hardLimit: Mass;
}

/**
 * OptionalPromise is a return type for functions, that can either return a value or a promise of that value
 */
declare type OptionalPromise<T> = Promise<T> | T;

/**
 * A function that can be used to create an instance of T
 */
type BaseFactory<T> = () => OptionalPromise<T>;
/**
 * A function that can be used to determine if the contribution is disabled
 */
type DisableContribution = () => OptionalPromise<boolean>;
/**
 * Public API specifying available behaviors
 */
type BaseBehavior<T = unknown> = {
    /**
     * This factory is called to create a new ApplicationNode
     */
    factory: BaseFactory<T>;
    /**
     * A function that can be used to determine if the contribution is disabled
     */
    disabled?: DisableContribution;
};

/**
 * A function that can be used to create a script builder for application code
 */
type ApplicationCodeGenerator = (node: ApplicationNode, context: ApplicationContext) => OptionalPromise<ScriptBuilder>;
/**
 * A function that can be used to move between versions of an application node
 */
type ApplicationVersionController = (loadedNode: ApplicationNode, defaultNode: ApplicationNode, context: ApplicationContext) => OptionalPromise<ApplicationNode>;
/**
 * A function called whenever an application containing the node is loaded
 */
type OnApplicationLoadHook = (node: ApplicationNode) => void;
/**
 * The list of tool controller identifiers
 */
type ToolControllers = (node: ApplicationNode) => OptionalPromise<ToolController[]>;
/**
 * The tool control information for a given tool controller
 */
type ToolControlInfo = (node: ApplicationNode, toolController: ToolController) => OptionalPromise<ToolControl>;
/**
 * Public API specifying available behaviors for the application
 */
type ApplicationBehaviors = BaseBehavior<ApplicationNode> & {
    /**
     * This function is called to generate urscript that will be put at the start of the program sent to the robot.
     * It will appear before any urscript generated for program nodes.
     */
    generatePreamble?: ApplicationCodeGenerator;
    /**
     * This function is called to upgrade a node when the node data model has been changed.
     * For example, if you have added a new mandatory field to your ApplicationNode, this function should
     * be used to give a default value to all existing nodes
     */
    upgradeNode?: ApplicationVersionController;
    /**
     * @deprecated Downgrading application nodes is not supported
     */
    downgradeNode?: ApplicationVersionController;
    /**
     * This function is called when the application is loaded
     */
    onLoad?: OnApplicationLoadHook;
    /**
     * This function is called for a list of identifiers, if this behavior can be a controller of the tool I/O.
     * The user will be able to select from this list on the Tool I/O screen, and the selected identifier used to
     * query for a tool configuration
     */
    toolControllers?: ToolControllers;
    /**
     * This function should return the tool control information for the given tool controller
     */
    toolControlInfo?: ToolControlInfo;
};

/**
 * AllowedInLogicProgram is a function that determines if the node is allowed in logic programs
 *
 * @returns true if the node is allowed in logic programs
 * @experimental
 */
type AllowedInLogicProgram = () => OptionalPromise<boolean>;
/**
 * CodeGenerator is a function that generates the code for the node
 *
 * @param node The ProgramNode to generate code for
 * @param context The Context object providing access to other nodes
 * @param applicationContext Provides access to application specific configuration
 * @returns A ScriptBuilder containing the generated script code
 */
type CodeGenerator<T> = (node: T, context: ScriptContext, applicationContext: ApplicationContext) => OptionalPromise<ScriptBuilder>;
/**
 * Validator function that takes a ProgramNode and validates it
 * @param node A ProgramNode to validate
 * @param context Context for tree traversing
 * @param applicationContext Provides access to application specific configuration
 * @returns
 */
type Validator<T> = (node: T, context: ValidationContext, applicationContext: ApplicationContext) => OptionalPromise<ValidationResponse>;
/**
 * ProgramNodeLabel function that takes a ProgramNode and returns a label for the tree
 * @param node The node to generate the label for
 * @returns the label for the node
 */
type ProgramNodeLabel<T> = (node: T) => OptionalPromise<ProgramLabel>;
/**
 * ChildInsertionRule function defines if a given parent can have a child of the given type
 * @param parent The programNode that becomes parent, for the newly inserted child, if the operation is allowed
 * @param childType Type of node to insert.
 * @returns true if the insertion operation succeeded
 */
type ChildInsertionRule = (parent: ProgramNode, childType: string) => OptionalPromise<boolean>;
/**
 * ContextInsertionRule function defines if a program node can be inserted in the given context
 * @param context InsertionContext providing access to surrounding tree nodes, where the node would be inserted
 * @returns whether the node is allowed to be inserted
 */
type ContextInsertionRule = (context: InsertionContext) => OptionalPromise<boolean>;
/**
 * A function that can be used to move between versions of a program node
 */
type ProgramVersionController<T> = (loadedNode: T) => OptionalPromise<T>;
/**
 * ProgramNodeLifeCycleEventType is a string that describes the lifecycle event that is being triggered
 */
type ProgramNodeLifeCycleEventType = 'delete' | 'paste' | 'suppress' | 'unsuppress' | 'copy' | 'undo' | 'redo' | 'load' | 'unload';
/**
 * ProgramBehaviors describes the possible behaviors defined by program node.
 * The object will be registered by calling {@link registerProgramBehavior}
 *
 */
type ProgramBehaviors<ProgramNodeSubtype extends ProgramNode = ProgramNode> = BaseBehavior<ProgramNodeSubtype | BranchNode> & {
    /**
     * Opt-in flag to allow this node in logic programs. Defaults to false.
     * @experimental
     */
    allowedInLogicProgram?: AllowedInLogicProgram;
    /**
     * The function that is called to generate the program node label. This is what is displayed in the
     * program tree when the node is not the selected node.
     *
     */
    programNodeLabel: ProgramNodeLabel<ProgramNodeSubtype>;
    /**
     * The urscript to generate for your program node. Any urscript generated by this function will appear before
     * the urscript generated for this node's children
     */
    generateCodeBeforeChildren?: CodeGenerator<ProgramNodeSubtype>;
    /**
     * The urscript to generate for your program node. Any urscript generated by this function will appear after
     * the urscript generated for this node's children
     */
    generateCodeAfterChildren?: CodeGenerator<ProgramNodeSubtype>;
    /**
     * The urscript to generate for your program node. This urscript will be generated after that of application nodes,
     * but before the before start
     */
    generateCodePreamble?: CodeGenerator<ProgramNodeSubtype>;
    /**
     * A function that validates the node. If the isValid return is false, the node will be marked in the invalid
     * colour in the tree, and the program cannot be played
     */
    validator?: Validator<ProgramNodeSubtype>;
    /**
     * A function that determines if a node of a given type can be inserted as a child of the passed in node
     */
    allowsChild?: ChildInsertionRule;
    /**
     * A function that determines if a node can be inserted at a given point in the tree.
     * For example, the 'else' node can only be inserted if the 'if' node was it's previous sibling
     */
    allowedInContext?: ContextInsertionRule;
    /**
     * This function is called to upgrade a node when the node data model has been changed.
     * For example, if you have added a new mandatory field to your ProgramNode, this function should
     * be used to give a default value to all existing nodes
     */
    upgradeNode?: ProgramVersionController<ProgramNodeSubtype>;
    /**
     * This function is called when an event in the ProgramNode's lifecycle occurs. For example, delete or paste.
     * As an example, it could be used on paste to make sure any internal ids continue to be unique
     */
    onLifeCycleHook?: LifeCycleEvent<ProgramNodeLifeCycleEventType, SubtreeNode>;
};

/**
 * A function which generates the script code required to get
 * the value of a signal.
 */
type GetSignalCodeGenerator = (source: Source, signal: Signal) => OptionalPromise<ScriptBuilder>;
/**
 * A function which generates the script code require to set
 * the value of a signal.
 */
type SetSignalCodeGenerator = (source: Source, signal: Signal, value: SignalValue) => OptionalPromise<ScriptBuilder>;
/**
 * A function called whenever an application containing the node is loaded
 */
type OnSourceLoadHook = (node: SourcesNode) => void;
/**
 * A function that can be used to create a script builder for source code
 */
type SourceCodeGenerator = (node: SourcesNode) => OptionalPromise<ScriptBuilder>;
/**
 * A function for continuously publishing the values of signals
 * NB: Must send current state on subscribe
 */
type ValuePublisher = (sourceID: string, signalFilter?: SignalFilter) => Observable<SignalEvent>;
/**
 * A function for setting the value of a given signal
 */
type ValueSetter = (sourceID: string, signalID: string, value: SignalValue) => void;
/**
 * A function for moving between versions of a sources node
 */
type SourcesVersionController = (loadedNode: SourcesNode) => OptionalPromise<SourcesNode>;
/**
 * Callback function for when the data model of a sources node changes
 */
type SourcesNodeChange = (node: SourcesNode) => void;
/**
 * A function for adding/removing sources
 */
type SourcesFactory = (sourceName: string) => OptionalPromise<Source>;
/**
 * Generates a label for a given SourcesNode.
 * @param node The SourcesNode for which the label is generated.
 * @returns A promise that resolves to the generated label.
 */
type SourcesNodeLabel = (node: SourcesNode) => OptionalPromise<string>;
/**
 * Returns info about the signals for a given source
 * It is used by the set and wait node to give the units and range limits for
 * analog signals
 * @param node The SourcesNode for which the info will be generated
 * @param sourceID The ID of the source for the signals
 * @returns A map of signal ID to SignalDomainData
 */
type SignalsDomainDataGenerator = (node: SourcesNode, sourceID: string) => OptionalPromise<Record<string, ValueRange>>;
/**
 *  Validates that the values will be okay for creating a set
 */
type SetSignalValidator = (sourceID: string, signalID: string, value: SignalValue) => OptionalPromise<ValidationResponse>;
/**
 *  Validates that the values will be okay for creating a get
 */
type GetSignalValidator = (sourceID: string, signalID: string, value: SignalValue, operator: string) => OptionalPromise<ValidationResponse>;
/**
 * SourceBehaviors describes the possible behaviors defined by the source.
 * The object will be registered by calling {@link registerSourceBehavior}
 */
type SourceBehaviors = Omit<BaseBehavior<SourcesNode>, 'factory'> & {
    factory?: BaseFactory<SourcesNode>;
    generateSetSignal?: SetSignalCodeGenerator;
    generateGetSignal?: GetSignalCodeGenerator;
    onLoad?: OnSourceLoadHook;
    generatePreamble?: SourceCodeGenerator;
    getSignalUpdates?: ValuePublisher;
    onSourcesChange?: SourcesNodeChange;
    upgradeNode?: SourcesVersionController;
    setSignalValue?: ValueSetter;
    generateLabel?: SourcesNodeLabel;
    generateSignalsDomainData?: SignalsDomainDataGenerator;
    validateSetSignal?: SetSignalValidator;
    validateGetSignal?: GetSignalValidator;
};
/**
 * Describing possible behaviours of a dynamic sources node
 */
type DynamicSourceBehaviors = SourceBehaviors & {
    generateSource: SourcesFactory;
};

/**
 * CodeGenerator is a function that generates the code for the smart skill
 *
 * @param instance The configured settings for the smart skill instance
 * @returns A ScriptBuilder containing the generated script code
 */
type SmartSkillsCodeGenerator = (instance: SmartSkillInstance) => OptionalPromise<ScriptBuilder>;
/**
 * Preamble Code Generator is a function that is run once per type of smart skill,
 * that generates code to be added to the main preamble
 *
 * @returns A ScriptBuilder containing the generated script code
 */
type StartSmartSkillsPreambleCodeGenerator = (instance: SmartSkillInstance) => OptionalPromise<ScriptBuilder>;
/**
 * Generates a program node from the data collected by recording the RTDE data,
 * during execution of the smart skill
 *
 * @param data The RTDE data collected during execution
 * @returns A programnode to be added to the programtree if recording is active
 */
type SmartSkillsProgramNodeGenerator = (instance: SmartSkillInstance, data: SmartSkillsData[]) => OptionalPromise<ProgramNode>;
/**
 * Validator is a function that validates the smart skill instance
 * @param instance The configured settings for the smart skill instance
 * @returns A ValidationResponse containing the validation result
 */
type SmartSkillsValidator = (instance: SmartSkillInstance) => OptionalPromise<ValidationResponse>;
/**
 * CodeGenerator is a function that generates the code for the smart skill
 *
 * @param instance The configured settings for the smart skill instance
 * @param data The data object containing the recorded data
 * @returns A ScriptBuilder containing the generated script code
 */
type SmartSkillsUndoRedoGenerator = (instance: SmartSkillInstance, data: SmartSkillsData[]) => OptionalPromise<ScriptBuilder>;
/**
 * SmartSkillInstanceVersionController is a function that upgrades the smart skill instance to a new version
 * @param loadedSmartSkillInstance The loaded smart skill instance
 * @returns A SmartSkillInstance containing the upgraded instance
 */
type SmartSkillInstanceVersionController = (loadedSmartSkillInstance: SmartSkillInstance) => OptionalPromise<SmartSkillInstance>;
/**
 * SmartSkillsLifeCycleEventType is an enum that describes the lifecycle event that is being triggered
 */
declare enum SmartSkillsLifeCycleEventType {
    /** Triggered when a smart skill instance has been created as a result of duplication from another instance */
    Duplicated = "duplicated",
    /** Triggered when a smart skill instance is renamed */
    Rename = "rename"
}
/**
 * SmartSkillsBehaviors describes the possible behaviors defined by a smart skill.
 * The object will be registered by calling {@link registerSmartSkillBehavior}
 *
 */
type SmartSkillBehaviors = BaseBehavior<SmartSkillInstance> & {
    startExecution: SmartSkillsCodeGenerator;
    stopExecution?: SmartSkillsCodeGenerator;
    generateProgramPreamble?: StartSmartSkillsPreambleCodeGenerator;
    generateInstanceProgramPreamble?: StartSmartSkillsPreambleCodeGenerator;
    createProgramNode?: SmartSkillsProgramNodeGenerator;
    validator?: SmartSkillsValidator;
    undo?: SmartSkillsUndoRedoGenerator;
    redo?: SmartSkillsUndoRedoGenerator;
    upgradeSmartSkillInstance?: SmartSkillInstanceVersionController;
    onLifeCycleHook?: LifeCycleEvent<SmartSkillsLifeCycleEventType, SmartSkillInstance>;
};

/**
 * A function that can be used to create a script builder for operator screen code
 */
type OperatorScreenCodeGenerator = (operatorScreen: OperatorScreen) => OptionalPromise<ScriptBuilder>;
/**
 * Validator function that takes an operator screen instance and validates it
 * @param operatorScreen An OperatorScreen to validate
 * @returns If the operator screen is valid. The program cannot be played if isValid is false
 */
type OperatorScreenValidator = (operatorScreen: OperatorScreen) => OptionalPromise<ValidationResponse>;
/**
 * A function that can be used to move between versions of an OperatorScreen
 */
type OperatorScreenVersionController = (loadedOperatorScreen: OperatorScreen) => OptionalPromise<OperatorScreen>;
/**
 * OperatorScreenBehaviors describes the possible behaviors defined by operator screens.
 * The object will be registered by calling {@link registerOperatorScreenBehavior}
 *
 */
type OperatorScreenBehaviors = BaseBehavior<OperatorScreen> & {
    /**
     * A function that will generate the urscript for the operator screen.
     */
    generatePreamble?: OperatorScreenCodeGenerator;
    /**
     * A function that returns if the operator screen is valid. If false, the operator screen icon will be marked in
     * the invalid colour, and the program cannot be played
     */
    validator?: OperatorScreenValidator;
    /**
     * This function is called to upgrade an operator screen when the data model has been changed.
     * For example, if you have added a new mandatory field to your OperatorScreen, this function should
     * be used to give a default value to the existing screen
     */
    upgrade?: OperatorScreenVersionController;
};

/**
 * A function that can be used to move between versions of a Sidebar item
 * @param {SidebarItem} loadedItem The source item
 * @param {SidebarItem} defaultItem The fallback item
 * @returns {OptionalPromise<SidebarItem>} The upgraded Sidebar item
 */
type VersionController = (loadedItem: SidebarItem, defaultItem: SidebarItem) => OptionalPromise<SidebarItem>;
/**
 * Public API specifying available behaviors for the Sidebar item
 */
type SidebarItemBehaviors = BaseBehavior<SidebarItem> & {
    /**
     * This function is called to upgrade a sidebar item when the data model has been changed.
     * For example, if you have added a new mandatory field to your SidebarItem, this function should
     * be used to give a default value to the existing screen
     */
    upgrade?: VersionController;
};

/**
 * LifeCycleEvent is a function that is called on specific life cycle events, usually triggered by user actions
 *
 * @param event The event that is being triggered
 * @param data The data associated with the event
 * @returns Optionally returns modified data, or undefined if no changes were made
 */
type LifeCycleEvent<eventType, dataType> = (event: eventType, data: dataType) => OptionalPromise<dataType | undefined>;

/**
 * Common description properties for all symbols
 */
type CommonSymbolDescription = {
    name: string;
    programNodeMetadata?: ProgramNodeMetadata;
    isDeleted?: boolean;
};
/**
 * Metadata specific to the entities that are declared by a program node
 */
type ProgramNodeMetadata = {
    programNodeId: string;
    isSuppressed: boolean;
    isThread?: boolean;
};
/**
 * Metadata specific to the entities that need to know which module they belong to
 */
type ModuleMetadata = {
    moduleName?: string;
};

