    constructor(history?: HistoryPolicy, depth?: number, reliability?: ReliabilityPolicy, durability?: DurabilityPolicy, deadline?: Duration, lifespan?: Duration, liveliness?: LivelinessPolicy, liveliness_lease_duration?: Duration, avoid_ros_namespace_conventions?: boolean);
